<!DOCTYPE html><html><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"/><title>Log Aktivitas</title><style>body{font-family:Arial,sans-serif;font-size:10px;}table{width:100%;border-collapse:collapse;}th,td{border:1px solid #000;padding:4px;text-align:left;}th{background-color:#f0f0f0;font-weight:bold;}h2{text-align:center;}</style></head><body><h2>Log Aktivitas</h2><table><thead><tr><th>No</th><th>Tanggal</th><th>Pengguna</th><th>Role</th><th>Aktivitas</th><th>Detail</th><th>IP</th></tr></thead><tbody>@foreach($activities as $activity)<tr><td>{{$loop->iteration}}</td><td>{{$activity->created_at->format("d-m-Y H:i:s")}}</td><td>{{$activity->user?->nama_pengguna??$activity->user?->name??"Dihapus"}}</td><td>{{$activity->user?->role??"-"}}</td><td>{{$activity->aktivitas}}</td><td>{{$activity->detail??"-"}}</td><td>{{$activity->ip_address??"-"}}</td></tr>@endforeach</tbody></table><p style="text-align:right;margin-top:20px;">Dicetak: {{date("d-m-Y H:i:s")}}</p></body></html>